  ('aboriginal-f0899a01-moex-00337', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關「罪刑法定原則」之敘述，下列何者錯誤？', '["罪刑明確性的要求為罪刑法定原則的內涵之一", "絕對死刑未違反明確性原則，故應廣泛適用", "絕對不定期刑之規範方式，違反罪刑法定原則", "不利於行為人之類推適用，違反罪刑法定原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00338', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '刑法第2條第1項規定「行為後法律有變更者，適用行為時之法律。但行為後之法律有利於行為人者，適 用最有利於行為人之法律。」本項揭示何種刑法基本原則？', '["禁止溯及既往原則", "習慣法禁止原則", "類推適用禁止原則", "罪疑惟輕原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00339', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲與A女分手後，在外不斷散播不利A的消息，讓A的現任男友乙不滿。某日，甲邀丙一起與乙談判， 甲認為乙無理取鬧，拿起桌上花瓶朝乙頭部丟擲，卻誤中一旁勸架的丙頭部，丙登時血流如注。甲的刑責 為何？', '["成立客體錯誤，論以傷害既遂罪", "成立打擊錯誤，論以過失傷害罪", "成立誤想防衛，論以過失傷害罪", "成立可避免之禁止錯誤，論以傷害罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00340', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '非從事業務之甲，明知不實事項而使不知情之從事業務之人乙，在其業務文書上登載不實，甲之刑責為何？', '["不成立犯罪", "刑法第215條業務登載不實罪之直接正犯", "刑法第215條業務登載不實罪之間接正犯", "刑法第215條業務登載不實罪之教唆犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00341', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲參加詐騙集團，於民國（下同）103年6月1日詐得新臺幣2萬元，甲分得2千元。104年12月30日 刑法沒收條文修正，該修正條文105年7月1日生效。甲被查獲後，經檢察官於107年1月18日起訴， 第一審法院於107年6月15日判決，則法院應依何時之法律沒收甲之犯罪所得？', '["105年7月1日修正生效前之法律", "105年7月1日修正生效後之法律", "原則上適用105年7月1修正生效前之法律，若修正後法律較有利，則適用修正後之法律", "原則上適用105年7月1修正生效後之法律，若修正前法律較有利，則適用修正前之法律"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00342', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲想要開槍射殺乙，卻將乙的雙胞胎兄弟丙誤認為乙而殺之，但又因槍法失準，未中丙，而擊中從丙身旁 經過的丁。甲之行為應如何論罪？', '["甲僅論處殺人罪", "甲僅論處過失致人於死罪", "甲論處過失致死罪與殺人未遂罪，想像競合", "甲論處過失致死罪與殺人未遂罪，數罪併罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00343', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於未遂犯，下列敘述何者正確？', '["進入預備階段時即成立未遂犯", "無論法律是否規定，均處罰未遂犯", "未遂犯之成立前提為著手實行犯行", "未遂犯之刑與既遂犯相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00344', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲計畫侵入乙之豪宅而竊取財物，依實務見解，甲之行為自何時起，即已達加重竊盜未遂罪之著手實行時點？', '["甲碰觸到財物時", "甲以眼睛搜尋、物色所要竊取之財物時", "甲將財物置於自己實力支配時", "甲侵入乙之豪宅時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00345', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲欲殺乙，惟於侵入乙宅後被乙發現，甲向乙揮砍一刀落空後，因重心不穩而摔倒，乙趁機逃離現場。甲 應構成殺人罪之何種未遂？', '["中止未遂", "不能未遂", "準中止未遂", "障礙未遂"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00346', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '對於下列之人，何者不屬於自首之對象？', '["司法警察", "檢察總長", "檢察官", "書記官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
